func handleOrderCreated(msg *sarama.ConsumerMessage) error {
    var event OrderCreated
    json.Unmarshal(msg.Value, &event)
    // Direct insert — duplicate delivery causes constraint violation or double charge
    _, err := db.Exec("INSERT INTO orders (id, amount) VALUES ($1, $2)",
        event.OrderID, event.Amount)
    return err
}
